#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=1e5+5;
int n,l[MAXN],r[MAXN],end,begin,t,q;
string s;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d",&t);
	while(t--){
		cin>>n>>q>>s;
		s=" "+s;
		bool flag1=false,flag2=false;
		for(int i=1;i<=n;++i){
			if(s[i]=='0'){
				l[i]=flag1;
				flag1=true;
			}
			else{
				l[i]=flag2;
				flag2=true;
			}
		}flag1=false,flag2=false;
		for(int i=n;i>=1;--i){
			if(s[i]=='0'){
				r[i]=flag1;
				flag1=true;
			}
			else{
				r[i]=flag2;
				flag2=true;
			}
		}
		for(int i=1,begin,end;i<=q;++i){
			cin>>begin>>end;
			if(begin==end)cout<<"No\n";
			else cout<<((l[begin]||r[end])?("Yes\n"):("No\n"));
		}
	}
	return false;
}
